<template>
    <div id="loginpage">
        <loadings :isLoading="settings.base.beforeLoad? 1: 0"></loadings>
        <div v-if="!settings.base.beforeLoad" >
            <NavBar :isActive="settings.base.belong" :isLogin="settings.base.isLogin" :user="settings.base.userInfo"></NavBar>
            <div class="container mundb-standard-container">
                <div class="row justify-content-sm-center">
                    <div class="col-sm-12 col-md-8 col-lg-6">
                        <div class="text-center" style="margin-top:10vh;margin-bottom:20px;">
                            <h1 style="padding:20px;display:inline-block;">Element OJ</h1>
                            <p>An Onlinejudger for Ctguacm</p>
                        </div>
                        <div class="card">
                            <div class="card-header">
                                <ul class="nav nav-tabs card-header-tabs nav-justified nav-tabs-material"
                                    id="accountTab"
                                    role="tablist">
                                    <li class="nav-item">
                                        <a class="nav-link active" id="login-tab" href="javascript:void(0)" role="tab">{{$t('DEFAULT.OJ_MESSAGE_LOGIN')}}</a>
                                    </li>
                                    <li class="nav-item">
                                        <a class="nav-link " id="register-tab"
                                           href="registerpage.html" role="tab">{{$t('DEFAULT.OJ_MESSAGE_REGISTER')}}</a>
                                    </li>
                                    <div class="nav-tabs-indicator" id="nav-tabs-indicator"></div>
                                </ul>
                            </div>
                            <div class="tab-content" id="accountTabContent">
                                <div class="tab-pane fade show active" role="tabpanel">
                                    <form class="needs-validation" id="login_form" @submit.prevent="postLoginForm()">
                                        <div class="card-body">
                                            <div class="form-group bmd-form-group"
                                                 v-bind:class="{ 'is-filled': forms.loginForm.account != '', 'is-focused': settings.loginForm.currentFocus == 'account' && settings.loginForm.hasFocus }">
                                                <label for="account" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_ACCOUNT')}}</label>
                                                <input type="text" name="account" class="form-control" id="account"
                                                       v-model="forms.loginForm.account" required
                                                       @focus="isLoginFormFocus('account')"
                                                       @blur="isLoginFormBlur();checkAccountData()"
                                                       @keyup="checkAccountData()"/>
                                                <span v-bind:style="{display: 'inline-block',float: 'right',color:result.loginForm.errorMessage.account==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.loginForm.hasFocus && settings.loginForm.currentFocus == 'account') || forms.loginForm.account.length > 0? '': 'hidden'}"
                                                      class="invalid-feedback"><strong>{{result.loginForm.errorMessage.account}}</strong></span>
                                                <div style="clear: both"></div>
                                            </div>
                                            <div class="form-group bmd-form-group"
                                                 v-bind:class="{ 'is-filled': forms.loginForm.password != '', 'is-focused': settings.loginForm.currentFocus == 'password' && settings.loginForm.hasFocus }">
                                                <label for="password" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_PASSWORD')}}</label>
                                                <input type="password" class="form-control" id="password"
                                                       autocomplete="off"
                                                       required="required" v-model="forms.loginForm.password"
                                                       @focus="isLoginFormFocus('password')"
                                                       @blur="isLoginFormBlur();checkPasswordData()"
                                                       @keyup="checkPasswordData()">
                                                <span v-bind:style="{display: 'inline-block',float: 'right',color:result.loginForm.errorMessage.password==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.loginForm.hasFocus && settings.loginForm.currentFocus == 'password') || forms.loginForm.password.length > 0? '': 'hidden'}"
                                                      class="invalid-feedback"><strong>{{result.loginForm.errorMessage.password}}</strong></span>
                                                <div style="clear: both"></div>
                                            </div>
                                            <template v-if="settings.hasVcode == true">
                                                <div style="float: left;width: 65%" class="form-group bmd-form-group"
                                                     v-bind:class="{ 'is-filled': forms.inputs.vcode != '', 'is-focused': settings.loginForm.currentFocus == 'vcode' && settings.loginForm.hasFocus }">
                                                    <label for="vcode" class="bmd-label-floating">{{$t('DEFAULT.OJ_MESSAGE_VERIFICATION_CODE')}}</label>
                                                    <input type="password" class="form-control" id="vcode"
                                                           autocomplete="off"
                                                           required="required" v-model="forms.inputs.vcode"
                                                           @focus="isLoginFormFocus('vcode')"
                                                           @blur="isLoginFormBlur();checkVcodeData()"
                                                           @keyup="checkVcodeData()">
                                                    <span v-bind:style="{display: 'inline-block',float: 'right',color:result.loginForm.errorMessage.vcode==$t('WARN.OJ_MESSAGE_ACCEPTABLE')? 'green':'', visibility: (settings.loginForm.hasFocus && settings.loginForm.currentFocus == 'vcode') || forms.inputs.vcode.length > 0? '': 'hidden'}"
                                                          class="invalid-feedback"><strong>{{result.loginForm.errorMessage.vcode}}</strong></span>
                                                    <div style="clear: both"></div>
                                                </div>
                                                <!---->
                                                <div style="float: right;width: 30%;margin-top: 21px;margin-right: 10px;">
                                                    <img ref="vcode_img" @click="getVcodeImage()"
                                                         style="cursor: pointer"/>
                                                </div>
                                                <div style="clear: both"></div>
                                            </template>

                                            <div class="form-group bmd-form-group">
                                                <div class="checkbox">
                                                    <label for="remember" class="is-filled">
                                                        <input class="form-control" type="checkbox" name="remember"
                                                               id="remember" value="rememberme"
                                                               v-model="forms.loginForm.rememberMe">
                                                        <span class="checkbox-decorator">
                                                        <span class="check"></span>
                                                    </span>
                                                        <span>{{$t('DEFAULT.OJ_MESSAGE_REMEMBER_ME')}}</span>
                                                    </label>
                                                </div>
                                            </div>
                                        </div>
                                        <div class="card-footer text-right">
                                            <a href="javascript:void(0)">
                                                <button type="button" class="btn btn-secondary">
                                                    {{$t('DEFAULT.OJ_MESSAGE_FORGET_PASSWORD')}}
                                                </button>
                                            </a>
                                            <button type="submit" class="btn btn-danger">
                                                {{$t('DEFAULT.OJ_MESSAGE_LOGIN')}}
                                            </button>
                                            <!--<div @click="test">55</div>-->
                                        </div>
                                    </form>
                                    <!--<button @click="submit_img" type="button" class="btn btn-secondary">&lt;!&ndash;&ndash;&gt;-->
                                    <!--&lt;!&ndash;&ndash;&gt;<span>上传图片</span>-->
                                    <!--</button>-->
                                    <!--<input @change="test" type="file" name="file" accept="image/*" class="el-upload__input"-->
                                    <!--ref="imgs">-->
                                </div>
                            </div>
                            <!--<div class="text-center card-bottom socialite-section">{{test}}</div>-->
                            <!--<img src="http://localhost:8081/OnlineJudge/vcode" ref="codeimg"/>-->
                        </div>
                    </div>
                </div>
            </div>
            <template v-if="result.loginForm.modelOpen == true">
                <div class="modal fade" id="login_error" tabindex="-1" role="dialog"
                     aria-labelledby="login_error_title" aria-hidden="true">
                    <div class="modal-dialog modal-dialog-centered" role="document">
                        <div class="modal-content">
                            <div class="modal-body">
                                <h3 style="color: #ff3f4c">
                                    {{$t('WARN.OJ_MESSAGE_UNSUCCESSFULLY_LOGIN')}}
                                </h3>
                                <br>
                                <p>{{result.loginForm.loginInfo}}</p>
                            </div>
                            <div class="modal-footer">
                                <button type="button" class="btn btn-secondary"
                                        data-dismiss="modal" @click="closeLoginInfoModel()">
                                    OK
                                </button>
                            </div>
                        </div>

                    </div>
                </div>
            </template>
            <footers></footers>
        </div>

    </div>
</template>
<script>
    import {hex_md5} from '@/assets/js/md5.js'
    import NavBar from "@/components/navbar/navbar";
    import fun from '@/assets/js/OJFunction'
    import Footers from "@/components/footer/footer";
    import Loadings from "@/components/loading/loading";

    export default {
        name: "loginpage",
        components: {Footers, NavBar, Loadings},
        data() {
            return {
                settings: {//页面配置
                    base: {//基本信息
                        belong: "account",
                        beforeLoad: true,
                        isLogin: false,
                        user: new Object(),
                    },
                    loginForm: {//登陆表单设置
                        currentFocus: '', //当前聚焦的表单项
                        hasFocus: false, //是否可以聚焦表单项
                    },
                    hasVcode: false,//页面是否有验证码
                },
                forms: {
                    loginForm: { //登陆输入信息表单
                        account: "",
                        password: "",
                        rememberMe: "",
                        vcode: "",
                        csrf: ""
                    }
                },
                result: {//表单及页面结果
                    loginForm: {
                        isLogining: false,
                        hasError: false,
                        loginInfo: "",
                        errorMessage: {
                            account: "　l",
                            password: "　",
                            vcode: "　"
                        },
                        modelOpen: false
                    },
                },
            }
        },
        methods: {
            submit_img: function () {
                this.$refs.imgs.click();
            },
            // handleSuccess(response, file, fileList) {
            //     response;
            //     file;
            //     fileList;
            //     this.$success("上传成功");
            // },
            // handleError() {
            //     this.$error("上传失败,请重新上传图片!");
            // },
            // handleBeforeUpload(file) {
            //     const isImage = file.type.includes("image");
            //     if (!isImage) {
            //         this.$message.error("上传文件类型必须是图片!");
            //     }
            //     const isLt2M = file.size / 1024 / 1024 < 2;
            //     if (!isLt2M) {
            //         this.$message.error("上传图片大小不能超过 2MB!");
            //     }
            //     return isImage && isLt2M;
            // },
            // handleProgress(event, file, fileList) {
            //     event;
            //     file;
            //     fileList;
            //     this.loading = true;  //  上传时执行loading事件
            // },
            // test: function () {
            //     var fromdata = new FormData();
            //     fromdata.append("file", this.$refs.imgs.files[0]);
            //     console.log(fromdata.get("file"));
            //     this.$http.post(this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/updata',
            //         fromdata, {contentType: false, processData: false}).then(function (res) {
            //         // alert(res);r
            //         res;
            //     }, function () {
            //         console.log('请求失败处理');
            //     });
            // },
            postLoginForm: function () {
                // console.log(this.inputs);
                this.result.loginForm.modelOpen = false;
                this.result.loginForm.loginInfo = "";
                this.result.loginForm.isLogining = true;
                this.result.loginForm.hasError = false;
                this.forms.loginForm.password = hex_md5(this.forms.loginForm.password);
                var _this = this;
                console.log(_this.forms.loginForm)
                window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/account/login', fun.stringify(_this.forms.loginForm)).then(function (res) {
                    let data = res.data
                    _this.result.loginForm.isLogining = false;
                    var error_type = data.OJ_ERROR_TYPE;
                    if (error_type != _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                        _this.result.loginForm.hasError = true;
                        var error_times = Number(data.OJ_LOGIN_ERROR_TIMES);
                        if (error_times >= _this.GLOBAL.OJ_DEFAULT_NEED_VCODE_TIMES) _this.getVcodeImage();
                        _this.forms.loginForm.password = "";
                    }
                    if (error_type == _this.GLOBAL.OJ_ERROR_IP_BE_BANNED) {
                        _this.result.loginForm.loginInfo = _this.$t('WARN.OJ_MESSAGE_IP_BE_BANNED');
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_WRONG_VCODE) {
                        _this.forms.inputs.vcode = "";
                        $("#vcode").focus();
                        _this.result.loginForm.errorMessage.vcode = _this.$t('WARN.OJ_MESSAGE_WRONG_VCODE');
                        _this.getVcodeImage();
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_ACCOUNT_BE_BANNED) {
                        _this.result.loginForm.loginInfo = _this.$t('WARN.OJ_MESSAGE_ACCOUNT_BE_BANNED');
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_NON_EXISTENT_ACCOUNT) {
                        $("#account").focus();
                        _this.result.loginForm.errorMessage.account = _this.$t('WARN.OJ_MESSAGE_NON_EXISTENT_ACCOUNT');
                        document.getElementById('account').setCustomValidity(_this.$t('WARN.OJ_MESSAGE_NON_EXISTENT_ACCOUNT'));
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_REPETED_ACCOUNT) {
                        $("#account").focus();
                        _this.result.loginForm.errorMessage.account = _this.$t('WARN.OJ_MESSAGE_REPETED_ACCOUNT');
                        document.getElementById('account').setCustomValidity(_this.$t('WARN.OJ_MESSAGE_REPETED_ACCOUNT'));
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_ACCOUNT_BE_BANNED) {
                        _this.result.loginForm.loginInfo = _this.$t('WARN.OJ_MESSAGE_ACCOUNT_BE_BANNED');
                    } else if (error_type == _this.GLOBAL.OJ_ERROR_WRONG_PASSWORD) {
                        $("#password").focus();
                        _this.result.loginForm.errorMessage.password = _this.$t('WARN.OJ_MESSAGE_WRONG_PASSWORD');
                        document.getElementById('password').setCustomValidity(_this.$t('WARN.OJ_MESSAGE_WRONG_PASSWORD'));
                    } else if (error_type != _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                        _this.result.loginForm.loginInfo = _this.$t('WARN.OJ_MESSAGE_BACK_JUMP');
                    }
                    if (_this.result.loginForm.loginInfo.length > 0) {
                        _this.result.loginForm.modelOpen = true;
                        setTimeout(function () {
                            $('#login_error').modal({
                                backdrop: 'static'
                            })
                        }, 100)
                    }

                    var remember_me = data.OJ_USER_INFO.saved;
                    if (_this.result.loginForm.hasError == false) {

                        var access_token = data.OJ_ACCESS_TOKEN;
                        var refresh_token = data.OJ_REFRESH_TOKEN;

                        if (remember_me) {
                            fun.setCookieWithTime("AccessToken", access_token, 0.025);
                            fun.setCookieWithTime("RefreshToken", refresh_token, 7);
                        } else {
                            fun.setCookie("AccessToken", access_token);
                            fun.setCookie("RefreshToken", refresh_token);
                        }
                        window.history.go(-1);
                    }
                }).catch(function (error) {
                    console.log(error)
                })

            },
            isLoginFormFocus: function (num) {
                this.settings.loginForm.currentFocus = num;
                this.settings.loginForm.hasFocus = true;
            },
            isLoginFormBlur: function () {
                this.settings.loginForm.hasFocus = false;
            },
            checkAccountData: function () {
                var data = document.getElementById('account');
                this.result.loginForm.errorMessage.account = "　";
                data.setCustomValidity("");
            },
            checkPasswordData: function () {
                var data = document.getElementById('password');
                this.result.loginForm.errorMessage.password = "　";
                data.setCustomValidity("");
            },
            checkVcodeData: function () {
                var data = document.getElementById('vcode');
                this.result.loginForm.errorMessage.vcode = "　";
                data.setCustomValidity("");
            },
            getVcodeImage: function () {
                this.settings.hasVcode = true;
                this.$http.post(this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/vcode',
                    {}, {responseType: 'arraybuffer'}).then(function (res) {
                    var url = 'data:image/png;base64,' + btoa(new Uint8Array(res.data).reduce((data, byte) => data + String.fromCharCode(byte), ''));
                    this.$refs.vcode_img.src = url;
                }, function () {
                    console.log('请求失败处理');
                });
            },
            closeLoginInfoModel: function () {
                var _this = this;
                setTimeout(function () {
                    _this.result.loginForm.modelOpen = false;
                    _this.result.loginForm.loginInfo = "";
                }, 300)
            },
            identify: async function () {
                let data = await fun.idenfity();
                this.$i18n.locale = data.OJ_LANGUAGE_TYPE;
                if (data.OJ_ERROR_TYPE == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                    this.settings.base.isLogin = true;
                    this.settings.base.userInfo = data.OJ_USER_INFO;
                }
                return data;
            },
            searchLoginSettings() {
                var _this = this
                return window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/account/login/settings', {}, {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                })
            }
        },
        async created() {
            this.settings.hasVcode = false;
            let res = await this.identify();
            if (res.OJ_ERROR_TYPE == this.GLOBAL.OJ_ERROR_NO_ERROR) {
                window.history.go(-1);
                return;
            }
            var _this = this
            window.axios.all([_this.searchLoginSettings()])
                .then(window.axios.spread((LoginRes) => {
                    let LoginData = LoginRes.data;
                    _this.forms.loginForm.csrf = LoginData.OJ_LOGIN_CSRF;
                    var error_times = Number(LoginData.OJ_LOGIN_ERROR_TIMES);
                    if (error_times >= this.GLOBAL.OJ_DEFAULT_NEED_VCODE_TIMES) _this.getVcodeImage();
                    _this.settings.base.beforeLoad = false;
                }))
                .catch((error) => {
                    console.log(error)
                })
        }
    }
</script>
<style lang="scss" scoped>
    #loginpage {
        .modal-body {
            h3 {
                font-weight: bold;
                font-family: 'Roboto-slab';
                margin-bottom: 0.5rem;
            }
            p {
                /*color: rgba(0, 0, 0, 0.54);*/
                margin-bottom: 0.5rem;
                margin-top: 0.5rem;
                font-weight: bold;
            }
        }
        .mundb-standard-container {
            flex-shrink: 0;
            flex-grow: 1;
        }
        .card {
            margin-bottom: 20vh;
            overflow: hidden;
            display: block;
            box-shadow: rgba(0, 0, 0, 0.1) 0px 0px 30px;
            border-radius: 4px;
            transition: .2s ease-out .0s;
            color: #7a8e97;
            background: #fff;
            position: relative;
            border: 1px solid rgba(0, 0, 0, 0.15);
        }
        .card-body {
            .form-group {
                margin-bottom: 0px;
            }
        }
        .card .card-header {
            padding: 0;
        }
        #accountTab {
            position: relative;
        }
        .card .card-header > ul {
            margin: 0;
        }
        .card .card-header > ul .nav-link {
            padding: 1rem;
            border: none !important;
            font-weight: bold;
        }
        .card .card-header .nav-tabs .nav-link.active {
            color: #ff4081;
        }
        .card-bottom {
            background-color: rgb(244, 244, 244);
            padding: 10px;
        }
        .nav-tabs-material .nav-tabs-indicator {
            background-color: #ff4081;
            bottom: -1px;
            display: block;
            width: 50%;
            height: .15rem;
            position: absolute;
            transition: .2s ease-out .0s;
        }
        form {
            margin-bottom: 0;
        }
        .checkbox {
            margin-top: 1rem;
        }
        .card-footer {
            border: none;
        }
    }
</style>